"use strict";
import { PortfolioLogo } from "components/AccountDrawer/MiniPortfolio/PortfolioLogo";
import { DeltaArrow } from "components/Tokens/TokenDetails/Delta";
import { NATIVE_CHAIN_ID } from "constants/tokens";
import { getTokenDetailsURL } from "graphql/data/util";
import { useCurrency } from "hooks/Tokens";
import { useScreenSize } from "hooks/screenSize/useScreenSize";
import { Computer } from "pages/Landing/components/Icons";
import { PillButton } from "pages/Landing/components/cards/PillButton";
import ValuePropCard from "pages/Landing/components/cards/ValuePropCard";
import { useNavigate } from "react-router-dom";
import { Flex, Text } from "ui/src";
import { LDO, UNI, USDC_BASE } from "uniswap/src/constants/tokens";
import { useTokenPromoQuery } from "uniswap/src/data/graphql/uniswap-data-api/__generated__/types-and-hooks";
import { UniverseChainId } from "uniswap/src/features/chains/types";
import { toGraphQLChain } from "uniswap/src/features/chains/utils";
import { t } from "uniswap/src/i18n";
import { NumberType, useFormatter } from "utils/formatNumbers";
const tokens = [
  { chainId: UniverseChainId.Mainnet, address: "ETH" },
  { chainId: UniverseChainId.Base, address: USDC_BASE.address },
  { chainId: UniverseChainId.Mainnet, address: UNI[UniverseChainId.Mainnet].address },
  { chainId: UniverseChainId.Mainnet, address: LDO.address }
];
function Token({ chainId, address }) {
  const screenIsSmall = useScreenSize()["sm"];
  const navigate = useNavigate();
  const { formatFiatPrice, formatDelta } = useFormatter();
  const currency = useCurrency(address, chainId);
  const tokenPromoQuery = useTokenPromoQuery({
    variables: {
      address: currency?.wrapped.address,
      chain: toGraphQLChain(chainId)
    }
  });
  const price = tokenPromoQuery.data?.token?.market?.price?.value ?? 0;
  const pricePercentChange = tokenPromoQuery.data?.token?.market?.pricePercentChange?.value ?? 0;
  return <Flex
    width="100%"
    height={48}
    overflow="hidden"
    py={12}
    px={16}
    row
    alignItems="center"
    gap="$gap12"
    borderRadius={12}
    onPress={(e) => {
      e.stopPropagation();
      navigate(
        getTokenDetailsURL({
          address: address === "ETH" ? NATIVE_CHAIN_ID : address,
          chain: toGraphQLChain(chainId)
        })
      );
    }}
    $platform-web={{
      transition: "background-color var(--dur-fast, 150ms) ease, transform var(--dur-fast, 150ms) ease",
      cursor: "pointer"
    }}
    hoverStyle={{
      backgroundColor: "rgba(11, 4, 24, 0.04)",
      x: 2
    }}
  >
    <PortfolioLogo currencies={[currency]} chainId={chainId} size={screenIsSmall ? 28 : 28} />
    <Flex row flex={1} justifyContent="space-between" gap="$gap16" alignItems="center">
      <Flex row width="auto" gap="$gap8" alignItems="center" overflow="hidden">
        <Text
          fontWeight="$medium"
          fontSize={16}
          lineHeight={24}
          overflow="hidden"
          whiteSpace="nowrap"
          textOverflow="ellipsis"
          color="var(--brand-950, #160A2E)"
        >{currency?.name}</Text>
        <Text fontWeight="$book" fontSize={14} lineHeight={20} color="rgba(46, 16, 101, 0.7)">{currency?.symbol}</Text>
      </Flex>
      <Flex row width="auto" gap="$gap8" alignItems="center">
        <Text
          className="font-mono"
          fontWeight="$medium"
          fontSize={16}
          lineHeight={20}
          color="var(--brand-950, #160A2E)"
        >{formatFiatPrice({ price, type: NumberType.FiatTokenPrice })}</Text>
        <Flex row gap="$gap4" alignItems="center" $md={{ display: "none" }}>
          <DeltaArrow delta={pricePercentChange} />
          <Text
            className="font-mono"
            fontSize={13}
            lineHeight={16}
            fontWeight="$medium"
            color={pricePercentChange < 0 ? "$statusCritical" : "$statusSuccess"}
          >{formatDelta(pricePercentChange)}</Text>
        </Flex>
      </Flex>
    </Flex>
  </Flex>;
}
export function WebappCard() {
  return <ValuePropCard
    to="/tokens/ethereum"
    minHeight={500}
    button={<PillButton
      label={t("common.webApp")}
      icon={<Computer size="24px" fill="var(--brand-500, #8B5CF6)" />}
    />}
    titleText={t("landing.swapSimple")}
  ><Flex
    gap="$gap8"
    alignItems="center"
    position="absolute"
    width="100%"
    bottom={0}
    p={32}
    pb={32}
    $xl={{ p: 24, pb: 32 }}
    $xs={{ p: 16, pb: 24 }}
  >{tokens.map((token) => <Token key={`tokenRow-${token.address}`} chainId={token.chainId} address={token.address} />)}</Flex></ValuePropCard>;
}
